1	/**
2	 * Wooricapital Auto Recommendation Prototype
3	 * 고객별 맞춤형 자동차 추천 + 자연어 검색
4	 */
5	
6	// ============================================
7	// 전역 변수
8	// ============================================
9	
10	let allCustomers = [];
