64	
65	// ============================================
66	// 초기화
67	// ============================================
68	
69	document.addEventListener('DOMContentLoaded', async function () {
70	    console.log('페이지 로드 완료. 데이터 로딩...');
71	
72	    try {
73	        // 데이터 로드
74	        await loadCustomers();
75	        await loadProducts();
76	
77	        // 첫 번째 고객으로 자동 설정 (선택 모달 표시)
78	        showCustomerSelection();
79	
80	        // 검색 이벤트 리스너
81	        const searchInput = document.getElementById('search-input');
82	        if (searchInput) {
83	            searchInput.addEventListener('input', handleSearch);
84	            searchInput.addEventListener('keypress', (e) => {
85	                if (e.key === 'Enter') {
86	                    handleSearch();
87	                }
88	            });
89	        }
90	
91	    } catch (error) {
92	        console.error('데이터 로드 실패:', error);
93	    }
94	});
95	
96	// ============================================
97	// 데이터 로드
98	// ============================================
99	
100	async function loadCustomers() {
101	    try {
